    def tick(self, now_ts: float | None = None) -> StreamResponse | None:
        """Check for an idle timeout and, if triggered, emit a terminal chunk.

        This should be called periodically by the streaming system. If `idle_timeout_s` is set and no chunk
        has been received for at least that long since the stream started, this emits a `StreamResponse` with
        an empty `chunk` to signal that the stream has stalled, then resets the listener state.

        Args:
            now_ts: The current timestamp to compare against the last received chunk's timestamp. Defaults to
                `time.monotonic()` when not provided.
        """
        if self.idle_timeout_s is None or not self.stream_start or self.stream_end or self._last_chunk_ts is None:
            return None

        current_ts = now_ts if now_ts is not None else time.monotonic()
        if current_ts - self._last_chunk_ts < self.idle_timeout_s:
            return None

        timeout_response = StreamResponse(self.predict_name, self.signature_field_name, "")

        # The timeout itself terminates the stream, so we must unconditionally clear the listener state
        # here (regardless of `allow_reuse`) to avoid leaving it stuck mid-stream.
        self.stream_start = False
        self.stream_end = False
        self.cache_hit = False
        self.field_start_queue = []
        self.field_end_queue = Queue()
